public static boolean isJSIdentifier(String s) {
  int length = s.length();

  if (length == 0) {
    return false;
  }

  // First character must be valid JavaScript identifier start
  if (!isJSIdentifierStart(s.charAt(0))) {
    return false;
  }

  for (int i = 1; i < length; i++) {
    if (!isJSIdentifierPart(s.charAt(i))) {
      return false;
    }
  }

  return true;
}

private static boolean isJSIdentifierStart(char ch) {
  // JavaScript identifier start rules:
  // - Unicode letter (includes most alphabetic characters)
  // - $ 
  // - _
  // - Unicode escape sequences representing these characters
  return Character.isLetter(ch) || ch == '$' || ch == '_' || 
         Character.getType(ch) == Character.LETTER_NUMBER;
}

private static boolean isJSIdentifierPart(char ch) {
  // JavaScript identifier part rules include identifier start plus:
  // - Unicode combining marks
  // - Unicode digits
  // - Unicode connector punctuation
  // - <ZWNJ> and <ZWJ>
  return isJSIdentifierStart(ch) || 
         Character.isDigit(ch) ||
         Character.getType(ch) == Character.NON_SPACING_MARK ||
         Character.getType(ch) == Character.COMBINING_SPACING_MARK ||
         Character.getType(ch) == Character.CONNECTOR_PUNCTUATION ||
         ch == '\u200C' || // ZWNJ
         ch == '\u200D';   // ZWJ
}

