/**
 * Render the specified text as a wrapped block with preserved whitespace.
 */
protected void renderWrappedTextBlock(StringBuffer sb, int width, 
                                     int nextLineTabStop, String text)
{
    if (text == null) {
        return;
    }

    // Split the text into lines while preserving original line breaks and whitespace
    String[] lines = text.split("\n", -1); // -1 to preserve trailing empty lines

    for (int i = 0; i < lines.length; i++) {
        if (i > 0) {
            sb.append(getNewLine());
        }
        renderWrappedText(sb, width, nextLineTabStop, lines[i]);
    }
}

public void printWrapped(PrintWriter pw, int width, int nextLineTabStop, String text)
{
    // If this is footer text with explicit formatting, preserve the formatting
    if (text != null && text.contains("\n")) {
        // For multi-line text, print it as-is to preserve formatting
        pw.println(text);
    } else {
        StringBuffer sb = new StringBuffer(text.length());
        renderWrappedText(sb, width, nextLineTabStop, text);
        pw.println(sb.toString());
    }
}

