public static boolean containsAny(CharSequence cs, char[] searchChars) {
    if (isEmpty(cs) || ArrayUtils.isEmpty(searchChars)) {
        return false;
    }
    int csLength = cs.length();
    int searchLength = searchChars.length;

    for (int i = 0; i < csLength; i++) {
        char ch = cs.charAt(i);
        for (int j = 0; j < searchLength; j++) {
            if (searchChars[j] == ch) {
                // Check if this is a high surrogate that forms a supplementary character
                if (Character.isHighSurrogate(ch)) {
                    // If we're at the last character in cs, this can't form a valid pair
                    if (i < csLength - 1) {
                        char low = cs.charAt(i + 1);
                        if (Character.isLowSurrogate(low)) {
                            // This is part of a supplementary character, check if searchChars contains the full code point
                            int codePoint = Character.toCodePoint(ch, low);
                            for (int k = 0; k < searchLength; k++) {
                                // If searchChars contains the low surrogate, this might match
                                if (k != j && Character.isLowSurrogate(searchChars[k])) {
                                    int searchCodePoint = Character.toCodePoint(searchChars[j], searchChars[k]);
                                    if (searchCodePoint == codePoint) {
                                        return true;
                                    }
                                }
                            }
                            // Skip the next character since we already processed it as part of the supplementary pair
                            i++;
                        }
                    }
                } else if (!Character.isLowSurrogate(ch)) {
                    // Regular BMP character, not part of a surrogate pair
                    return true;
                }
                // If we get here with a low surrogate, it means it wasn't preceded by a high surrogate
                // so it's an invalid sequence, but we'll treat it as a regular character match
                return true;
            }
        }
    }
    return false;
}

